from flask import Flask, redirect, url_for, request, session, render_template_string
import json
import requests

app = Flask(__name__)

@app.route('/login')
def login():
    authorization_url = f"{config['oidc_config']['authorization_endpoint']}" \
        f"?client_id={config['oidc_config']['client_id']}&" \
        f"redirect_uri={config['oidc_config']['redirect_uri']}&" \
        f"response_type=id_token&scope=openid"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    token_endpoint = config['oidc_config']['token_endpoint']
    client_id = config['oidc_config']['client_id']
    client_secret = config['oidc_config']['client_secret']
    id_token_hint = request.args.get('id_token')

    auth_response = requests.post(
        url=token_endpoint,
        data={
            'grant_type': 'authorization_code',
            'code': request.args.get('code'),
            'redirect_uri': config['oidc_config']['redirect_uri'],
            'client_id': client_id
        },
        headers={'Content-Type': 'application/x-www-form-urlencoded'}
    )

    if auth_response.status_code == 200:
        auth_data = json.loads(auth_response.text)
        session['token'] = auth_data['access_token']
        return render_template_string('<p>You are now logged in!</p>')
    else:
        return render_template_string('<p>Login failed.</p>')

